```python
from traitlets import *

class Foo(HasTraits):
    bar = EDict()
    
    @observe('bar', type='element_set')
    def o_change(self, change):
        print(change)

    @observe('bar', type='element_del')
    def o_changes(self, change):
        print(change)

foo = Foo()

foo.bar['key'] = 'value'
del foo.bar['key']
```
